contracts/PredictionMarket.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract PredictionMarket is ReentrancyGuard, Ownable {
    struct Market {
        uint256 id;
        string question;
        uint256 endTime;
        uint256 minBet;
        uint256 maxBet;
        uint256 yesPool;
        uint256 noPool;
        bool resolved;
        bool outcome;
        address creator;
        bool exists;
    }

    struct Bet {
        uint256 amount;
        bool side;
        bool claimed;
    }

    uint256 private marketIdCounter;
    uint256 public constant PLATFORM_FEE_BPS = 150; // 1.5% = 150 basis points
    uint256 public totalCollectedFees;

    mapping(uint256 => Market) public markets;
    mapping(uint256 => mapping(address => Bet)) public bets;
    mapping(uint256 => mapping(address => bool)) public hasBet;

    event MarketCreated(uint256 indexed marketId, string question, uint256 endTime, uint256 minBet, uint256 maxBet, address indexed creator);
    event BetPlaced(uint256 indexed marketId, address indexed user, uint256 amount, bool side);
    event MarketResolved(uint256 indexed marketId, bool outcome);
    event RewardClaimed(uint256 indexed marketId, address indexed user, uint256 amount);
    event PlatformFeesWithdrawn(uint256 amount);

    modifier marketExists(uint256 marketId) {
        require(markets[marketId].exists, "Market does not exist");
        _;
    }

    modifier marketOpen(uint256 marketId) {
        require(markets[marketId].exists, "Market does not exist");
        require(!markets[marketId].resolved, "Market is resolved");
        require(block.timestamp < markets[marketId].endTime, "Market has ended");
        _;
    }

    modifier marketEnded(uint256 marketId) {
        require(markets[marketId].exists, "Market does not exist");
        require(block.timestamp >= markets[marketId].endTime, "Market has not ended");
        _;
    }

    modifier marketResolved(uint256 marketId) {
        require(markets[marketId].exists, "Market does not exist");
        require(markets[marketId].resolved, "Market is not resolved");
        _;
    }

    function createMarket(string memory question, uint256 endTime, uint256 minBet, uint256 maxBet) external {
        require(endTime > block.timestamp, "End time must be in the future");
        require(minBet > 0, "Min bet must be greater than 0");
        require(maxBet > minBet, "Max bet must be greater than min bet");
        require(bytes(question).length > 0, "Question cannot be empty");

        marketIdCounter++;
        markets[marketIdCounter] = Market({
            id: marketIdCounter,
            question: question,
            endTime: endTime,
            minBet: minBet,
            maxBet: maxBet,
            yesPool: 0,
            noPool: 0,
            resolved: false,
            outcome: false,
            creator: msg.sender,
            exists: true
        });

        emit MarketCreated(marketIdCounter, question, endTime, minBet, maxBet, msg.sender);
    }

    function placeBet(uint256 marketId, bool side) external payable marketOpen(marketId) {
        require(!hasBet[marketId][msg.sender], "User has already bet on this market");
        require(msg.value >= markets[marketId].minBet, "Bet amount below minimum");
        require(msg.value <= markets[marketId].maxBet, "Bet amount above maximum");

        uint256 fee = (msg.value * PLATFORM_FEE_BPS) / 10000;
        uint256 amountAfterFee = msg.value - fee;
        totalCollectedFees += fee;

        bets[marketId][msg.sender] = Bet({
            amount: amountAfterFee,
            side: side,
            claimed: false
        });

        hasBet[marketId][msg.sender] = true;

        if (side) {
            markets[marketId].yesPool += amountAfterFee;
        } else {
            markets[marketId].noPool += amountAfterFee;
        }

        emit BetPlaced(marketId, msg.sender, amountAfterFee, side);
    }

    function resolveMarket(uint256 marketId, bool outcome) external onlyOwner marketEnded(marketId) {
        require(!markets[marketId].resolved, "Market already resolved");
        markets[marketId].resolved = true;
        markets[marketId].outcome = outcome;
        emit MarketResolved(marketId, outcome);
    }

    function claimReward(uint256 marketId) external nonReentrant marketResolved(marketId) {
        require(hasBet[marketId][msg.sender], "No bet found for this user");
        require(!bets[marketId][msg.sender].claimed, "Reward already claimed");

        Bet memory userBet = bets[marketId][msg.sender];
        Market memory market = markets[marketId];

        require(userBet.side == market.outcome, "User did not bet on winning side");

        uint256 totalPool = market.yesPool + market.noPool;
        uint256 winningPool = market.outcome ? market.yesPool : market.noPool;
        require(winningPool > 0, "Winning pool is empty");

        uint256 reward = (userBet.amount * totalPool) / winningPool;

        // Deduct 1.5% platform fee from reward
        uint256 fee = (reward * PLATFORM_FEE_BPS) / 10000;
        uint256 amountAfterFee = reward - fee;
        totalCollectedFees += fee;

        bets[marketId][msg.sender].claimed = true;

        (bool success, ) = payable(msg.sender).call{value: amountAfterFee}("");
        require(success, "Transfer failed");

        emit RewardClaimed(marketId, msg.sender, amountAfterFee);
    }

    function withdrawPlatformFees() external onlyOwner {
        require(totalCollectedFees > 0, "No fees to withdraw");
        uint256 amount = totalCollectedFees;
        totalCollectedFees = 0;

        (bool success, ) = payable(owner()).call{value: amount}("");
        require(success, "Platform fee transfer failed");

        emit PlatformFeesWithdrawn(amount);
    }

    function getMarket(uint256 marketId) external view returns (Market memory) {
        return markets[marketId];
    }

    function getUserBet(uint256 marketId, address user) external view returns (Bet memory) {
        return bets[marketId][user];
    }

    function hasUserBet(uint256 marketId, address user) external view returns (bool) {
        return hasBet[marketId][user];
    }

    function getMarketCount() external view returns (uint256) {
        return marketIdCounter;
    }

    function getOdds(uint256 marketId) external view returns (uint256 yesOdds, uint256 noOdds) {
        Market memory market = markets[marketId];
        uint256 totalPool = market.yesPool + market.noPool;
        if (totalPool == 0) {
            return (5000, 5000);
        }
        yesOdds = (market.yesPool * 10000) / totalPool;
        noOdds = (market.noPool * 10000) / totalPool;
    }

    function emergencyWithdraw() external onlyOwner {
        (bool success, ) = payable(owner()).call{value: address(this).balance}("");
        require(success, "Transfer failed");
    }

    function cancelMarket(uint256 marketId) external onlyOwner marketExists(marketId) {
        require(!markets[marketId].resolved, "Cannot cancel resolved market");
        markets[marketId].resolved = true;
    }

    receive() external payable {}
}

